        </rect>
      ))}
    </svg>
  );
}

function Ring(props: React.SVGProps<SVGSVGElement>) {
  return <LoaderIcon {...props} />;
}

function Spin({ className, ...props }: React.SVGProps<SVGSVGElement>) {
  return (
    <svg
