      </SelectContent>
    </SelectRoot>
  );
}

const SelectSearch = CommandInput;

export {
  Select,
  SelectRoot,
  SelectTrigger,
  SelectSearch,
  SelectContent,
  SelectItem,
  SelectGroup,
  SelectLabel,
  SelectSeparator,
  SelectHeader,
};

