const cardVariants = cva("relative overflow-hidden", {
  variants: {
    variant: {
      soft: "",
      solid: "",
      outline: "border",
      glass: "backdrop-blur-sm",
      gradient: "",
    },
    tone: {
      neutral: "",
      primary: "",
      destructive: "",
      success: "",
      warning: "",
    },
    radius: {
      none: "rounded-none",
      sm: "rounded-sm",
      md: "rounded-md",
      lg: "rounded-lg",
      xl: "rounded-xl",
      "2xl": "rounded-2xl",
      full: "rounded-full",
    },
    shadow: {
      none: "shadow-none",
      sm: "shadow-sm",
      md: "shadow-md",
      lg: "shadow-lg",
    },
    padding: {
      none: "p-0",
      sm: "p-3",
      md: "p-6",
      lg: "p-8",
    },
  },
  compoundVariants: [
    {
      variant: "soft",
      tone: "neutral",
      className: "bg-card text-card-foreground",
    },
    {
      variant: "soft",
      tone: "primary",
      className: "bg-primary/20 text-primary-foreground",
    },
    {
      variant: "soft",
      tone: "destructive",
      className: "bg-destructive/20 text-destructive-foreground",
    },
    {
      variant: "soft",
      tone: "success",
      className: "bg-success/20 text-success-foreground",
    },
    {
      variant: "soft",
      tone: "warning",
      className: "bg-warning/20 text-warning-foreground",
    },

    {
      variant: "solid",
      tone: "neutral",
      className: "bg-card-foreground text-card-foreground",
    },
    {
      variant: "solid",
      tone: "primary",
      className: "bg-primary text-primary-foreground",
    },
    {
      variant: "solid",
      tone: "destructive",
      className: "bg-destructive text-destructive-foreground",
    },
    {
      variant: "solid",
      tone: "success",
      className: "bg-success text-success-foreground",
    },
    {
      variant: "solid",
      tone: "warning",
      className: "bg-warning text-warning-foreground",
    },

    {
      variant: "outline",
      tone: "neutral",
      className: "bg-transparent border-border text-card-foreground",
    },
    {
      variant: "outline",
      tone: "primary",
      className: "bg-transparent border-primary/30 text-primary-foreground",
    },
    {
      variant: "outline",
      tone: "destructive",
      className:
        "bg-transparent border-destructive/30 text-destructive-foreground",
    },
    {
      variant: "outline",
      tone: "success",
      className: "bg-transparent border-success/30 text-success-foreground",
    },
    {
      variant: "outline",
      tone: "warning",
      className: "bg-transparent border-warning/30 text-warning-foreground",
    },

    {
      variant: "glass",
      tone: "neutral",
      className: "bg-foreground/6 border border-foreground/6 text-foreground",
    },
    {
      variant: "glass",
      tone: "primary",
      className:
        "bg-primary/10 border border-primary/20 text-primary-foreground",
    },
    {
      variant: "glass",
      tone: "destructive",
      className:
        "bg-destructive/10 border border-destructive/20 text-destructive-foreground",
    },
    {
      variant: "glass",
      tone: "success",
      className:
        "bg-success/10 border border-success/20 text-success-foreground",
    },
    {
      variant: "glass",
      tone: "warning",
      className:
