    },
    {
      variant: "gradient",
      tone: "primary",
      className: "bg-linear-to-tr from-primary/30 to-primary/25",
    },
    {
      variant: "gradient",
      tone: "destructive",
      className:
        "bg-linear-to-b from-red-900/30 to-red-900/10 ring-1 ring-red-700/30 border border-red-800/20",
    },
    {
      variant: "gradient",
      tone: "success",
      className:
