"use client";

import React, { useState } from "react";
import type {
  SliderProps as SliderPrimitiveProps,
  SliderThumbProps,
} from "react-aria-components";
import {
  composeRenderProps,
  SliderOutput,
  Slider as SliderPrimitive,
  SliderStateContext,
  SliderThumb as SliderThumbPrimitive,
  SliderTrack as SliderTrackPrimitive,
  type SliderTrackProps,
} from "react-aria-components";
import { cva } from "class-variance-authority";
import { cn } from "@/lib/utils";
import { composeTailwindRenderProps } from "@/lib/render-props";
import { Description, Label } from "@/components/ui/core/field";
import { Tooltip, TooltipContent } from "@/components/ui/core/tooltip";

interface SliderProps extends SliderPrimitiveProps {
  output?: "inline" | "tooltip" | "none";
  label?: string;
  description?: string;
  thumbLabels?: string[];
}

function Slider({
  output = "inline",
  orientation = "horizontal",
  className,
  ...props
}: SliderProps) {
  const showTooltip = output === "tooltip";
  const [showTooltipState, setShowTooltipState] = useState(false);

  const onFocusChange = () => {
    if (showTooltip) setShowTooltipState(true);
  };

  const onHoverStart = () => {
    if (showTooltip) setShowTooltipState(true);
  };

  const onFocusEnd = React.useCallback(() => {
    setShowTooltipState(false);
  }, []);

  React.useEffect(() => {
    if (showTooltip) {
      window.addEventListener("pointerup", onFocusEnd);
      return () => {
        window.removeEventListener("pointerup", onFocusEnd);
      };
    }
  }, [showTooltip, onFocusEnd]);

  function renderThumb(index: number) {
    const thumb = (
      <SliderThumb
        index={index}
        aria-label={props.thumbLabels?.[index]}
        onFocusChange={onFocusChange}
        onHoverStart={onHoverStart}
      />
    );

    if (!showTooltip) return thumb;

    return (
      <Tooltip
        delay={0}
        isOpen={showTooltipState}
        onOpenChange={setShowTooltipState}
      >
        {thumb}
        <TooltipContent
          showArrow={false}
          offset={orientation === "horizontal" ? 8 : -100}
          crossOffset={orientation === "horizontal" ? -55 : 0}
          className="min-w-6 px-1.5 py-1 text-xs"
          placement={orientation === "vertical" ? "right" : "top"}
        >
          <SliderOutput />
        </TooltipContent>
      </Tooltip>
    );
  }

  return (
    <SliderPrimitive
      aria-label={props.label || props["aria-label"] || "slider"}
      orientation={orientation}
      className={composeRenderProps(className, (className, { orientation }) =>
        cn(
          "group relative flex touch-none select-none flex-col disabled:opacity-50",
          orientation === "horizontal" && "w-full min-w-56 gap-y-2",
          orientation === "vertical" &&
            "h-full min-h-56 w-1.5 items-center gap-y-2",
          className
        )
      )}
      {...props}
    >
      <div className="flex text-foreground">
        {props.label && <Label>{props.label}</Label>}
        {output === "inline" && (
          <SliderOutput className="text-muted-foreground text-sm tabular-nums data-[orientation=vertical]:mx-auto data-[orientation=horizontal]:ml-auto">
            {({ state }) =>
              state.values
                .map((_, i) => state.getThumbValueLabel(i))
                .join(" – ")
            }
          </SliderOutput>
        )}
      </div>
      <SliderTrack>
        {({ state }) => (
          <>
            <SliderFiller />
            {state.values.map((_, i) => (
              <React.Fragment key={i}>{renderThumb(i)}</React.Fragment>
            ))}
          </>
        )}
      </SliderTrack>
      {props.description && <Description>{props.description}</Description>}
    </SliderPrimitive>
  );
}

function SliderTrack({ className, ...props }: SliderTrackProps) {
  return (
    <SliderTrackPrimitive
      {...props}
      className={composeTailwindRenderProps(
        className,
        cn(
          "group/track relative cursor-default rounded-full bg-muted disabled:cursor-default disabled:opacity-60",
          "grow group-data-[orientation=horizontal]:h-1.5 group-data-[orientation=horizontal]:w-full group-data-[orientation=vertical]:w-1.5 group-data-[orientation=vertical]:flex-1"
        )
      )}
    />
  );
}

function SliderFiller({
  className,
  ...props
}: React.HTMLAttributes<HTMLDivElement>) {
  const state = React.useContext(SliderStateContext);
  const { orientation, getThumbPercent, values } = state || {};

  const getStyle = () => {
    const percent0 = getThumbPercent ? getThumbPercent(0) * 100 : 0;
    const percent1 = getThumbPercent ? getThumbPercent(1) * 100 : 0;

    if (values?.length === 1) {
      return orientation === "horizontal"
        ? { width: `${percent0}%` }
        : { height: `${percent0}%` };
    }

    return orientation === "horizontal"
      ? {
          left: `${percent0}%`,
          width: `${Math.abs(percent0 - percent1)}%`,
        }
      : {
          bottom: `${percent0}%`,
          height: `${Math.abs(percent0 - percent1)}%`,
        };
  };

  return (
    <div
      {...props}
      style={getStyle()}
      className={cn(
        "group-data-[orientation=horizontal]/top-0 pointer-events-none absolute rounded-full bg-primary group-disabled/track:opacity-60 group-data-[orientation=vertical]/track:bottom-0 group-data-[orientation=horizontal]/track:h-full group-data-[orientation=vertical]/track:w-full",
        className
      )}
    />
  );
}

const thumbStyles = cva(
  "top-[50%] left-[50%] size-[1.25rem] rounded-full border border-foreground/10 bg-white outline-hidden ring-black transition-[width,height]",
  {
    variants: {
      isFocusVisible: {
        true: "border-primary outline-hidden ring-ring/20",
      },
      isDragging: {
        true: "size-[1.35rem] cursor-grabbing border-primary",
      },
      isDisabled: {
        true: "opacity-50 forced-colors:border-[GrayText]",
      },
    },
  }
);

function SliderThumb({ className, ...props }: SliderThumbProps) {
  return (
    <SliderThumbPrimitive
      {...props}
      className={composeRenderProps(className, (className, renderProps) =>
        thumbStyles({ ...renderProps, className })
      )}
    />
  );
}

export type { SliderProps };
export { Slider, SliderFiller, SliderTrack, SliderThumb };

