        <line opacity="0.083" x1="1750" y1="247.4" x2="1500" y2="680.4" />
        <animateTransform
          attributeName="transform"
          attributeType="XML"
          type="rotate"
          keyTimes="0;0.08333;0.16667;0.25;0.33333;0.41667;0.5;0.58333;0.66667;0.75;0.83333;0.91667"
          values="0 1199 1199;30 1199 1199;60 1199 1199;90 1199 1199;120 1199 1199;150 1199 1199;180 1199 1199;210 1199 1199;240 1199 1199;270 1199 1199;300 1199 1199;330 1199 1199"
          dur="0.83333s"
          begin="0.08333s"
          repeatCount="indefinite"
          calcMode="discrete"
        />
      </g>
    </svg>
  );
}

const LOADERS = {
  bars: Bars,
  ring: Ring,
  spin: Spin,
};

const DEFAULT_SPINNER = "spin";

interface LoaderProps
  extends
    Omit<
      React.ComponentPropsWithoutRef<"svg">,
      "display" | "opacity" | "color"
    >,
    LoaderVariantProps {
  type?: keyof typeof LOADERS;
  percentage?: number;
  isInfinite?: boolean;
  formatOptions?: Intl.NumberFormatOptions;
  ref?: React.RefObject<SVGSVGElement>;
}

function Loader({ isInfinite = true, ref, ...props }: LoaderProps) {
  const {
    className,
    type = DEFAULT_SPINNER,
    color,
    size,
    ...spinnerProps
  } = props;

  const LoaderPrimitive = LOADERS[type in LOADERS ? type : DEFAULT_SPINNER];

  return (
    <ProgressBar
      data-slot="loader"
      aria-label={props["aria-label"] ?? "Loading..."}
      formatOptions={props.formatOptions}
      isIndeterminate={isInfinite}
    >
      <LoaderPrimitive
        role="presentation"
        ref={ref}
        {...spinnerProps}
        className={cn(loaderStyles({ color, size }), [
          type === "ring" && "animate-spin",
          type === "spin" && "stroke-current",
          className,
        ])}
      />
    </ProgressBar>
  );
}

export { Loader, type LoaderProps };

