      )}
      {...props}
    >
      <RangeCalendar className="border-0 p-0" {...calendar} />
    </PopoverContent>
  );
}

function DateRangePickerTrigger() {
  return (
    <InputGroup
      className="*:data-input:flex-none [&>span]:shrink-0
