const PopoverFooter = DialogFooter;

export type { PopoverProps, PopoverContentProps };
export {
  Popover,
  PopoverTrigger,
  PopoverClose,
  PopoverDescription,
  PopoverContent,
  PopoverBody,
  PopoverFooter,
  PopoverHeader,
  PopoverTitle,
};

