              <Check data-slot="check-indicator" />
            ) : null;

            const content = hasCustomChildren ? (
              isStringChild ? (
                <Label>{children}</Label>
              ) : (
                <>{children}</>
              )
            ) : (
              <>
                {label && <Label>{label}</Label>}
                {description && <Description>{description}</Description>}
              </>
            );

            return (
              <div
                className={cn(
                  checkboxWrapper({ withDescription: !!description }),
                  className
                )}
              >
                <span
                  data-slot="indicator"
                  className={cn(
                    checkboxIndicator({
                      size,
                      isSelected,
                      isIndeterminate,
                      isFocusVisible,
                      isInvalid,
                      isDisabled,
