          ? "inset-y-0 top-[calc(1.5rem+0.125rem)] ltr:left-3 rtl:right-3 -translate-x-1/2 w-0.5 h-[calc(100%-1.5rem-0.25rem)]"
          : "inset-x-0 top-3 ltr:left-[calc(50%+0.75rem+0.125rem)] rtl:right-[calc(50%+0.75rem+0.125rem)] -translate-y-1/2 h-0.5 flex-1 w-[calc(100%-1.5rem-0.25rem)]",
        className
      )}
      {...props}
    >
      <div
