};

type AnimatedDockItemProps = {
  className?: string;
  children: React.ReactNode;
  onClick?: () => void;
};

type AnimatedDockLabelProps = {
  className?: string;
  children: React.ReactNode;
};

type AnimatedDockIconProps = {
  className?: string;
  children: React.ReactNode;
};

type AnimatedDockContextType = {
  mouseX: MotionValue;
  spring: SpringOptions;
  magnification: number;
  distance: number;
