        className="inline-block cursor-pointer"
      >
        {trigger}
      </div>

      <AnimatePresence>
        {isOpen && (
          <motion.div
            initial={animationConfig.initial}
            animate={animationConfig.animate}
            exit={animationConfig.exit}
            transition={getTransition()}
            className={cn(
              "absolute z-99999 pointer-events-none",
              "bg-popover text-foreground",
              "rounded-md shadow-md border",
              "px-3 py-2 text-sm",
              "whitespace-nowrap",
              getTooltipPosition()
            )}
            style={{
              [position === "top" || position === "bottom"
                ? "marginBottom"
                : "marginRight"]:
                position === "top"
                  ? `${offset}px`
                  : position === "bottom"
                    ? undefined
                    : position === "left"
                      ? `${offset}px`
                      : undefined,
              [position === "top" || position === "bottom"
                ? "marginTop"
                : "marginLeft"]:
                position === "bottom"
                  ? `${offset}px`
                  : position === "top"
                    ? undefined
                    : position === "right"
                      ? `${offset}px`
                      : undefined,
            }}
          >
            {children}

            {showArrow && (
              <div className={cn("absolute", getArrowPosition())}>
                <svg
                  width={8}
                  height={8}
                  viewBox="0 0 8 8"
                  className={cn("fill-popover", getArrowRotation())}
                  style={{ filter: "drop-shadow(0 -1px 1px rgba(0,0,0,0.1))" }}
                >
                  <path d="M 0 8 L 4 0 L 8 8 Z" />
                </svg>
              </div>
            )}
          </motion.div>
        )}
      </AnimatePresence>
    </div>
  );
}

export { AnimatedTooltip, type AnimatedTooltipProps, type AnimationStyle };

